params.script:
// Script Template: condition_group
// 入力モジュールの出力値をグループ番号に分類（多段分岐用）
// プレースホルダー: OpenAI_用件確認 = 入力元モジュール名（OpenAI モジュール）
// プレースホルダー: {"ワクチン": "1", "複数人": "1", "予約": "1", "確認": "1", "変更": "1", "キャンセル": "1", "検診": "1", "問い合わせ": "1", "other": "1"} = 値→グループ番号の JSON オブジェクト
// プレースホルダー: 1 = マッピングに該当しない場合のデフォルトグループ番号
// 出力: グループ番号文字列（"1", "2", ... "10"）

var input = $runner.getModuleResult("OpenAI_用件確認");
var mapping = {"ワクチン": "1", "複数人": "1", "予約": "1", "確認": "1", "変更": "1", "キャンセル": "1", "検診": "1", "問い合わせ": "1", "other": "1"};
var group = mapping[input];
if (!group) { group = "1"; }
$runner.setResult(group);
